#include <hexi/static_buffer.h>
#include <cstdint>

template<size_t buffer_size = 1024>
void write_uint32_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, uint32_t value) {
    buffer.write(hexi::endian::le(value));
}

template<size_t buffer_size = 1024>
uint32_t read_uint32_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer) {
    uint32_t value;
    buffer.read(hexi::endian::le(value));
    return value;
}
```

**Explanation:**

1. **Writing uint32_t to buffer:**
   - Uses `buffer.write()` method with `hexi::endian::le(value)` adaptor
   - The `le` adaptor converts the native-endian value to little-endian format before writing
   - This ensures proper byte ordering regardless of the host system's native endianness

2. **Reading uint32_t from buffer:**
   - Creates a `uint32_t value` variable to store the result
   - Uses `buffer.read()` method with `hexi::endian::le(value)` adaptor
   - The `le` adaptor reads the little-endian data from buffer and converts it to native-endian format
   - Returns the properly converted value

Both operations leverage the `static_buffer`'s built-in endian conversion capabilities through the `hexi::endian::le` adaptor, ensuring consistent binary representation across different platforms.

