        std::size_t remaining = adaptor.size();

        // Read a chunk of data (up to chunk_size or remaining, whichever is smaller)
        std::size_t to_read = std::min(remaining, chunk_size);
        std::vector<uint8_t> chunk(to_read);

        // Read the data using the read() function
        adaptor.read(chunk.data(), to_read);

