#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <span>

struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Convert message_id to big-endian and write using put() to avoid double conversion
    uint32_t be_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.put(be_message_id);

    // Write count of data_values in big-endian
    uint32_t count = static_cast<uint32_t>(packet.data_values.size());
    uint32_t be_count = hexi::endian::native_to_big(count);
    stream.put(be_count);

    // Convert data_values to big-endian and write using put()
    for (auto val : packet.data_values) {
        uint16_t be_val = hexi::endian::native_to_big(val);
        stream.put(be_val);
    }

    // Convert checksum to big-endian and write
    uint32_t be_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.put(be_checksum);

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    ProtocolPacket packet;

    // Read message_id using get() to avoid byte order conversion, then convert from big-endian to native
    uint32_t be_message_id;
    stream.get(be_message_id);
    packet.message_id = hexi::endian::big_to_native(be_message_id);

    // Read count of data_values
    uint32_t be_count;
    stream.get(be_count);
    uint32_t count = hexi::endian::big_to_native(be_count);

    // Read data_values and convert each element from big-endian to native
    packet.data_values.reserve(count);
    for (uint32_t i = 0; i < count; ++i) {
        uint16_t be_val;
        stream.get(be_val);
        packet.data_values.push_back(hexi::endian::big_to_native(be_val));
    }

    // Read checksum and convert from big-endian to native
    uint32_t be_checksum;
    stream.get(be_checksum);
    packet.checksum = hexi::endian::big_to_native(be_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    ProtocolHeader header;

    // Use span to get zero-copy view of message_id
    auto message_id_span = stream.span<uint32_t>(1);
    if (!message_id_span.empty()) {
        uint32_t be_message_id = message_id_span[0];
        header.message_id = hexi::endian::big_to_native(be_message_id);
    }

    // Skip past the header (span already advanced, but we can skip explicitly if needed)
    // stream.skip(sizeof(uint32_t)); // Not needed as span already advanced

    return header;
}

