struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (float temp : temperatures) {
            float converted = hexi::endian::conditional_reverse(
                temp, std::endian::native, std::endian::little
            );
            adaptor.write(converted);
        }

        // Convert and write pressure with runtime endianness conversion
        double converted_pressure = hexi::endian::conditional_reverse(
            pressure, std::endian::native, std::endian::little
        );
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read and convert each temperature from little-endian to native
        size_t count = adaptor.read_container(temperatures);
        for (float& temp : temperatures) {
